```class Solution {
public:
    vector<int> countBits(int n) {
        vector<int> ans(n + 1);
        ans[0] = 0;
        int powerOf2 = 1;
        int cnt = 0;
        for (int i = 1; i <= n; i++) {
            if (i == powerOf2) {
                ans[i] = 1;
                powerOf2 *= 2;
                cnt = 0;
            } else {
                ans[i] = ans[i - powerOf2 / 2 + cnt] + 1;
                cnt++;
            }
        }
        return ans;
    }
};
